#include <stdio.h>

int main() {
    int T; if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N; scanf("%d", &N);
        int degree = -1;
        for (int i = 0; i < N; ++i) {
            int a; scanf("%d", &a);
            if (a != 0) degree = i;
        }
        printf("%d\n", degree);
    }
    return 0;
}

